// 💾 INDEXEDDB SETUP
// ==========================================================================
const dbPromise = openDB('nouval-offline-db', 3, {
  upgrade(db, oldVersion) {
    if (oldVersion < 1) { db.createObjectStore('inventory', { keyPath: 'id' }); db.createObjectStore('transactions', { keyPath: 'id' }); db.createObjectStore('customers', { keyPath: 'id' }); db.createObjectStore('tickets', { keyPath: 'id' }); db.createObjectStore('settings', { keyPath: 'id' }); db.createObjectStore('warehouses', { keyPath: 'id' }); db.createObjectStore('employees', { keyPath: 'id' }); }
    if (oldVersion < 2) { const syncStore = db.createObjectStore('sync_queue', { keyPath: 'id', autoIncrement: true }); syncStore.createIndex('timestamp', 'timestamp'); syncStore.createIndex('attempts', 'attempts'); }
    if (oldVersion < 3) { db.createObjectStore('search_cache', { keyPath: 'term' }); db.createObjectStore('reports_cache', { keyPath: 'id' }); db.createObjectStore('backups', { keyPath: 'id' }); }
  },
});

export const offlineDB = {
  async save(store, data) { const db = await dbPromise; await db.put(store, data); return true; },
  async get(store, id) { const db = await dbPromise; return await db.get(store, id); },
  async getAll(store) { const db = await dbPromise; return await db.getAll(store); },
  async delete(store, id) { const db = await dbPromise; await db.delete(store, id); return true; },
  async clear(store) { const db = await dbPromise; await db.clear(store); return true; },
  async addToSyncQueue(operation) { const db = await dbPromise; return await db.add('sync_queue', { ...operation, timestamp: Date.now(), attempts: 0, lastAttempt: null }); },
  async getSyncQueue() { const db = await dbPromise; return await db.getAll('sync_queue'); },
  async updateSyncQueue(id, updates) { const db = await dbPromise; const item = await db.get('sync_queue', id); if (item) await db.put('sync_queue', { ...item, ...updates }); return true; },
  async removeFromSyncQueue(id) { const db = await dbPromise; await db.delete('sync_queue', id); return true; },
  async saveSearchCache(term, results) { const db = await dbPromise; await db.put('search_cache', { term, results, timestamp: Date.now() }); return true; },
  async getSearchCache(term) { const db = await dbPromise; const cached = await db.get('search_cache', term); if (cached && Date.now() - cached.timestamp < 5 * 60 * 1000) return cached.results; return null; },
  async syncWithServer() { const queue = await this.getSyncQueue(); let synced = 0, failed = 0; for (const item of queue) { if (item.attempts >= 5) { failed++; continue; } try { switch (item.type) { case 'add': await addDoc(collection(db, item.collection), item.data); break; case 'update': await updateDoc(doc(db, item.collection, item.id), item.data); break; case 'delete': await deleteDoc(doc(db, item.collection, item.id)); break; } await this.removeFromSyncQueue(item.id); synced++; } catch(e) { await this.updateSyncQueue(item.id, { attempts: item.attempts + 1, lastError: e.message }); failed++; } } return { synced, failed }; }
};

// ==========================================================================
// 🚦 RATE LIMITER
// ==========================================================================
class RateLimiter { constructor(limit, windowMs) { this.limit = limit; this.windowMs = windowMs; this.requests = new Map(); } check(key) { const now = Date.now(); const userRequests = this.requests.get(key) || []; const validRequests = userRequests.filter(time => now - time < this.windowMs); if (validRequests.length >= this.limit) return false; validRequests.push(now); this.requests.set(key, validRequests); return true; } getRemaining(key) { const now = Date.now(); const userRequests = this.requests.get(key) || []; const validRequests = userRequests.filter(time => now - time < this.windowMs); return Math.max(0, this.limit - validRequests.length); } reset(key) { this.requests.delete(key); } }
export const apiLimiter = new RateLimiter(60, 60000);

