function AdvancedCharts({ data, type = 'line', title, height = 300 }) { const colors = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8', '#82ca9d']; if (!data || data.length === 0) return <div className="text-center text-slate-400 py-8">لا توجد بيانات</div>; const chartData = data.map(item => ({ name: item.name || item.label || item.date, value: item.value || item.count || item.total })); const renderChart = () => { switch(type) { case 'line': return (<LineChart data={chartData}><CartesianGrid strokeDasharray="3 3" /><XAxis dataKey="name" /><YAxis /><Tooltip /><Legend /><Line type="monotone" dataKey="value" stroke="#8884d8" /></LineChart>); case 'bar': return (<BarChart data={chartData}><CartesianGrid strokeDasharray="3 3" /><XAxis dataKey="name" /><YAxis /><Tooltip /><Legend /><Bar dataKey="value" fill="#8884d8" /></BarChart>); case 'pie': return (<PieChart><Pie data={chartData} cx="50%" cy="50%" labelLine={false} label={entry => entry.name} outerRadius={80} fill="#8884d8" dataKey="value"><Cell /></Pie><Tooltip /></PieChart>); default: return null; } }; return (<div className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700">{title && <h3 className="font-bold text-lg mb-4 text-slate-800 dark:text-white">{title}</h3>}<ResponsiveContainer width="100%" height={height}>{renderChart()}</ResponsiveContainer></div>); }

