export const generateAPIKey = (user, permissions) => ({ id: 'key_' + Date.now().toString(36) + Math.random().toString(36).substr(2), key: CryptoJS.lib.WordArray.random(32).toString(), userId: user.id, userName: user.name, permissions, createdAt: new Date().toISOString(), expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(), lastUsed: null, isActive: true });
export const validateAPIKey = async (apiKey) => { try { const q = query(collection(db, 'api_keys'), where('key', '==', apiKey)); const snap = await getDocs(q); if (snap.empty) return { valid: false, error: 'مفتاح API غير صالح' }; const keyData = snap.docs[0].data(); if (!keyData.isActive) return { valid: false, error: 'مفتاح API معطل' }; if (new Date(keyData.expiresAt) < new Date()) return { valid: false, error: 'انتهت صلاحية المفتاح' }; await updateDoc(doc(db, 'api_keys', snap.docs[0].id), { lastUsed: serverTimestamp() }); return { valid: true, permissions: keyData.permissions }; } catch(e) { return { valid: false, error: 'خطأ في التحقق' }; } };

