const normalizeSearch = (str) => { if (!str) return ''; return String(str).toLowerCase().trim().replace(/\s+/g, ' '); };
const normalizeSerial = (str) => { if (!str) return ''; return String(str).trim().toUpperCase(); };
function useDebounce(value, delay) { const [debouncedValue, setDebouncedValue] = useState(value); useEffect(() => { const handler = setTimeout(() => setDebouncedValue(value), delay); return () => clearTimeout(handler); }, [value, delay]); return debouncedValue; }
const formatDate = (timestamp) => { if (!timestamp) return '-'; try { if (timestamp?.toDate) return timestamp.toDate().toLocaleString('ar-EG', { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }); return new Date(timestamp).toLocaleString('ar-EG'); } catch { return '-'; } };
const exportToCSV = (data, filename) => { if (!data || !data.length) return false; try { const headers = Object.keys(data[0]); const csvContent = ["\uFEFF" + headers.join(','), ...data.map(row => headers.map(f => { const val = row[f]; if (val === null || val === undefined) return ''; if (typeof val === 'string') return `"${val.replace(/"/g, '""')}"`; if (val instanceof Date) return `"${val.toLocaleString()}"`; return val; }).join(','))].join('\n'); const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' }); const link = document.createElement("a"); link.href = URL.createObjectURL(blob); link.download = `${filename}.csv`; link.click(); setTimeout(() => URL.revokeObjectURL(link.href), 100); return true; } catch(e) { console.error(e); return false; } };
const parseCSV = (text) => { try { const lines = text.split('\n').filter(line => line.trim()); if (lines.length === 0) return []; const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, '')); const results = []; for (let i = 1; i < lines.length; i++) { if (!lines[i].trim()) continue; let current = '', inQuotes = false; const values = []; for (let j = 0; j < lines[i].length; j++) { const char = lines[i][j]; if (char === '"') inQuotes = !inQuotes; else if (char === ',' && !inQuotes) { values.push(current.trim().replace(/^"|"$/g, '')); current = ''; } else current += char; } values.push(current.trim().replace(/^"|"$/g, '')); const row = {}; headers.forEach((header, index) => { row[header] = values[index] || ''; }); results.push(row); } return results; } catch(e) { console.error(e); return []; } };
const logUserActivity = async (user, action, details) => { if (!user) return; try { await addDoc(collection(db, 'activity_logs'), { userId: user.id, userName: user.name || user.email, userRole: user.role, action, details, timestamp: serverTimestamp() }); } catch(e) { console.error(e); } };
