// ==========================================================================
// 🏷️ TAG MANAGER
// ==========================================================================
class TagManager { constructor() { this.tags = new Map(); this.categories = new Set(); } async loadTags() { try { const snap = await getDocs(collection(db, 'tags')); this.tags.clear(); snap.docs.forEach(doc => { this.tags.set(doc.id, doc.data()); this.categories.add(doc.data().category); }); } catch(e) { console.error(e); } } async addTag(tag, category = 'general') { try { const tagId = tag.toLowerCase().replace(/\s+/g, '_'); await setDoc(doc(db, 'tags', tagId), { name: tag, category, usageCount: 0, createdAt: serverTimestamp() }); this.tags.set(tagId, { name: tag, category, usageCount: 0 }); this.categories.add(category); return tagId; } catch(e) { return null; } } async incrementUsage(tagId) { try { const tagRef = doc(db, 'tags', tagId); await updateDoc(tagRef, { usageCount: increment(1) }); } catch(e) { console.error(e); } } getTagsByCategory(category) { const result = []; this.tags.forEach((tag, id) => { if (tag.category === category) result.push({ id, ...tag }); }); return result; } getAllCategories() { return Array.from(this.categories); } searchTags(query) { const result = []; const lowerQuery = query.toLowerCase(); this.tags.forEach((tag, id) => { if (tag.name.toLowerCase().includes(lowerQuery)) result.push({ id, ...tag }); }); return result; } }
export const tagManager = new TagManager();

// ==========================================================================
// 🔔 NOTIFICATION SERVICE
// ==========================================================================
export const requestNotificationPermission = async () => { try { const permission = await Notification.requestPermission(); if (permission === 'granted' && messaging) { const token = await getToken(messaging, { vapidKey: import.meta.env.VITE_VAPID_KEY || '' }); const user = auth.currentUser; if (user) await setDoc(doc(db, 'fcm_tokens', user.uid), { token, device: getUserAgent(), timestamp: serverTimestamp() }, { merge: true }); return token; } } catch(e) { console.error(e); } return null; };
export const onMessageListener = () => new Promise((resolve) => { if (messaging) onMessage(messaging, (payload) => resolve(payload)); });

// ==========================================================================
// 🎹 اختصارات لوحة المفاتيح
// ==========================================================================
function useKeyboardShortcuts(handlers) { useEffect(() => { const handleKeyDown = (e) => { const key = `${e.ctrlKey ? 'ctrl+' : ''}${e.altKey ? 'alt+' : ''}${e.shiftKey ? 'shift+' : ''}${e.key.toLowerCase()}`; const shortcuts = { 'ctrl+f': handlers.onSearch, 'ctrl+n': handlers.onAdd, 'ctrl+s': handlers.onSave, 'f5': handlers.onRefresh, 'escape': handlers.onCancel, 'ctrl+d': handlers.onDashboard, 'ctrl+i': handlers.onInventory, 'ctrl+t': handlers.onTransactions, 'ctrl+c': handlers.onCustomers, 'ctrl+shift+e': handlers.onExport, 'ctrl+shift+p': handlers.onPrint, 'ctrl+shift+d': handlers.onBulkDelete }; if (shortcuts[key]) { e.preventDefault(); shortcuts[key](); } }; window.addEventListener('keydown', handleKeyDown); return () => window.removeEventListener('keydown', handleKeyDown); }, [handlers]); }

// ==========================================================================
// 🌙 DARK MODE
// ==========================================================================
const DARK_MODE_KEY = 'nouval_dark_mode'; const getInitialDarkMode = () => { const saved = localStorage.getItem(DARK_MODE_KEY); if (saved !== null) return saved === 'true'; return window.matchMedia('(prefers-color-scheme: dark)').matches; };
const useDarkMode = () => { const [isDark, setIsDark] = useState(getInitialDarkMode); useEffect(() => { if (isDark) document.documentElement.classList.add('dark'); else document.documentElement.classList.remove('dark'); localStorage.setItem(DARK_MODE_KEY, isDark); }, [isDark]); const toggle = () => setIsDark(!isDark); return { isDark, toggle }; };

// ==========================================================================
// 🔄 SYNC MANAGER
// ==========================================================================
const syncManager = { async syncAll() { return await offlineDB.syncWithServer(); }, async addOperation(operation) { if (navigator.onLine) { try { switch (operation.type) { case 'add': await addDoc(collection(db, operation.collection), operation.data); break; case 'update': await updateDoc(doc(db, operation.collection, operation.id), operation.data); break; case 'delete': await deleteDoc(doc(db, operation.collection, operation.id)); break; } return { synced: true }; } catch(e) { await offlineDB.addToSyncQueue(operation); return { synced: false, queued: true }; } } else { await offlineDB.addToSyncQueue(operation); return { synced: false, queued: true }; } }, startAutoSync(interval = 5 * 60 * 1000) { setInterval(async () => { if (navigator.onLine) await this.syncAll(); }, interval); } };

// ==========================================================================
// 🔍 SEARCH CACHE
// ==========================================================================
const searchCache = { async get(term, type) { return offlineDB.getSearchCache(`${type}:${term}`); }, async set(term, type, results) { return offlineDB.saveSearchCache(`${type}:${term}`, results); }, async search(term, type, searchFn) { const cached = await this.get(term, type); if (cached) return cached; const results = await searchFn(term); await this.set(term, type, results); return results; } };

// ==========================================================================
// 📊 VIRTUAL TABLE COMPONENT
// ==========================================================================
function VirtualTable({ data, columns, height = 600, rowHeight = 50 }) { const Row = ({ index, style }) => { const item = data[index]; return (<div style={style} className="flex border-b hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">{columns.map((col, idx) => (<div key={idx} className="p-3 text-sm truncate" style={{ width: col.width || `${100 / columns.length}%` }}>{col.render ? col.render(item) : item[col.field]}</div>))}</div>); }; return (<List height={height} itemCount={data.length} itemSize={rowHeight} width="100%">{Row}</List>); }

// ==========================================================================
// 🧾 مكون عرض الفاتورة المحسن
// ==========================================================================
function InvoiceRenderer({ data, systemSettings, onBack }) { const printRef = useRef(); const exportInvoiceImage = async () => { const element = document.getElementById("invoice-print"); if (!element) return; const canvas = await html2canvas(element); const image = canvas.toDataURL("image/png"); const link = document.createElement("a"); link.href = image; link.download = `invoice-${data.invoiceNumber}.png`; link.click(); }; useEffect(() => { const timer = setTimeout(() => window.print(), 800); return () => clearTimeout(timer); }, [data]); const template = systemSettings.invoiceTemplate || { showLogo: true, showStoreName: true, showCustomerInfo: true, showItems: true, showPrices: true, showDiscount: true, showTax: true, showFees: true, showFooter: true, showPaymentMethod: true, showNotes: true, showTechnician: true, fontSize: 'normal', paperSize: '80mm' }; const getPaperWidth = () => { switch(template.paperSize) { case '58mm': return 'max-w-[58mm]'; case '80mm': return 'max-w-[80mm]'; case 'A4': return 'max-w-[210mm]'; default: return 'max-w-[80mm]'; } }; const getFontSize = () => { switch(template.fontSize) { case 'small': return 'text-xs'; case 'large': return 'text-lg'; default: return 'text-sm'; } }; const formatCurrency = (value) => Number(value || 0).toLocaleString() + ' ج.م'; const handleSendWhatsApp = () => { if (data.phone) { const message = `فاتورة رقم ${data.invoiceNumber}\n`; const items = (data.items || []).map(item => `- ${item.name} × ${item.quantity || 1} = ${(item.price * (item.quantity || 1))} ج`).join('\n'); sendWhatsApp(data.phone, message + items + `\nالإجمالي: ${data.finalTotal} ج`); } }; const handleSendEmail = async () => { if (data.email) { await sendEmail(data.email, `فاتورة رقم ${data.invoiceNumber}`, generateInvoiceHTML(data, systemSettings)); showSuccess("تم إرسال الفاتورة إلى البريد الإلكتروني"); } }; return (<div id="invoice-print" className="flex justify-center p-6 bg-slate-100 dark:bg-slate-900 min-h-full print:bg-white" dir="rtl"><div ref={printRef} className={`bg-white dark:bg-slate-800 ${getPaperWidth()} w-full p-6 text-black dark:text-white border shadow-lg print:shadow-none print:border-none print:m-0 ${getFontSize()}`}>{template.showLogo && systemSettings.invoiceLogo && (<div className="text-center mb-4"><img src={systemSettings.invoiceLogo} alt="Logo" className="max-h-16 mx-auto" crossOrigin="anonymous" /></div>)}{template.showStoreName && (<div className="text-center border-b border-black dark:border-white border-dashed pb-4 mb-4"><h1 className="font-black text-xl">{systemSettings.storeName}</h1><p className="text-[11px] font-bold mt-1">فاتورة مبيعات #{data.invoiceNumber}</p><p className="text-[10px] mt-1 text-gray-600 dark:text-gray-400">{formatDate(data.date)}</p></div>)}{template.showCustomerInfo && (<div className="text-[11px] mb-4 space-y-1.5 font-bold text-right"><div className="flex justify-between"><span>العميل:</span><span>{data.customerName}</span></div><div className="flex justify-between"><span>الهاتف:</span><span dir="ltr">{data.phone || '-'}</span></div>{data.technicianName && <div className="flex justify-between"><span>الفني المختص:</span><span>{data.technicianName}</span></div>}{data.ticketId && <div className="flex justify-between"><span>رقم التذكرة:</span><span>{data.ticketId}</span></div>}<div className="flex justify-between text-gray-600 dark:text-gray-400"><span>الكاشير:</span><span>{data.operator}</span></div><div className="flex justify-between text-indigo-600 text-[10px] pt-1 border-t border-dashed"><span>الفرع/المركز:</span><span>{data.operatorCenter || 'الفرع الرئيسي'}</span></div>{data.notes && <div className="text-[9px] text-gray-500 dark:text-gray-500 mt-2">{data.notes}</div>}</div>)}{template.showItems && (<table className="w-full text-[11px] border-y border-black dark:border-white border-dashed py-2 mb-4 text-right"><thead><tr className="font-bold border-b border-gray-300 dark:border-gray-600"><th className="pb-2">الصنف</th><th className="pb-2 text-center">كمية</th>{template.showPrices && <th className="pb-2 text-left">السعر</th>}{template.showPrices && <th className="pb-2 text-left">الإجمالي</th>}</table></thead><tbody>{(data.items || []).map((item, idx) => (<tr key={idx}><td className="py-2 text-right font-bold">{item.name}<br/><span className="text-[9px] font-mono text-gray-500 dark:text-gray-500 mt-0.5 block">{item.serialNumber}</span></td><td className="text-center py-2 font-bold">{item.quantity || 1}</td>{template.showPrices && <td className="text-left py-2 font-black">{formatCurrency(item.price)}</td>}{template.showPrices && <td className="text-left py-2 font-black">{formatCurrency((item.price || 0) * (item.quantity || 1))}</td>}</tr>))}</tbody></table>)}{template.showPrices && (<div className="text-[11px] space-y-1.5 font-bold border-b border-black dark:border-white border-dashed pb-4 mb-4 text-right"><div className="flex justify-between"><span>المجموع الفرعي:</span><span>{formatCurrency(data.subtotal)}</span></div>{template.showDiscount && data.discountAmount > 0 && <div className="flex justify-between"><span>الخصم:</span><span>- {formatCurrency(data.discountAmount)}</span></div>}{template.showTax && data.taxAmount > 0 && <div className="flex justify-between"><span>الضريبة ({systemSettings.taxRate || 14}%):</span><span>+ {formatCurrency(data.taxAmount)}</span></div>}{template.showFees && data.installAmount > 0 && <div className="flex justify-between"><span>رسوم إضافية:</span><span>+ {formatCurrency(data.installAmount)}</span></div>}<div className="flex justify-between border-t border-black dark:border-white pt-2 mt-2 text-[14px] font-black"><span>الصافي المطلوب:</span><span>{formatCurrency(data.finalTotal)}</span></div>{template.showPaymentMethod && data.paymentMethod && <div className="flex justify-between text-[10px]"><span>طريقة الدفع:</span><span>{data.paymentMethod === 'cash' ? 'نقداً' : data.paymentMethod === 'card' ? 'بطاقة' : data.paymentMethod === 'transfer' ? 'تحويل' : data.paymentMethod}</span></div>}</div>)}{template.showFooter && (<div className="text-center text-[9px] font-bold italic text-gray-700 dark:text-gray-400 leading-relaxed"><p>{systemSettings.footerText || 'شكراً لتعاملكم معنا'}</p></div>)}<div className="mt-8 flex flex-wrap gap-2 print:hidden"><button onClick={() => window.print()} className="flex-1 bg-black text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 text-sm hover:bg-gray-800"><Printer size={16}/> طباعة</button><button onClick={exportInvoiceImage} className="flex-1 bg-indigo-600 text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 text-sm hover:bg-indigo-700"><ImageIcon size={16}/> تحميل صورة</button>{data.phone && <button onClick={handleSendWhatsApp} className="flex-1 bg-green-600 text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 text-sm hover:bg-green-700"><MessageCircle size={16}/> واتساب</button>}{data.email && <button onClick={handleSendEmail} className="flex-1 bg-blue-600 text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 text-sm hover:bg-blue-700"><Mail size={16}/> بريد</button>}<button onClick={onBack} className="flex-1 bg-slate-200 dark:bg-slate-700 text-slate-800 dark:text-white py-2.5 rounded-lg font-bold flex items-center justify-center gap-2 text-sm hover:bg-slate-300 dark:hover:bg-slate-600"><ArrowRightLeft size={16}/> إغلاق</button></div></div></div>); }

