// ==========================================================================
function InvoiceTemplateManager({ systemSettings, setSettings }) { const [template, setTemplate] = useState(systemSettings.invoiceTemplate || { showLogo: true, showStoreName: true, showCustomerInfo: true, showItems: true, showPrices: true, showDiscount: true, showTax: true, showFees: true, showFooter: true, showPaymentMethod: true, showNotes: true, showTechnician: true, fontSize: 'normal', paperSize: '80mm' }); const handleSave = async () => { try { await setDoc(doc(db, 'settings', 'general'), { invoiceTemplate: template }, { merge: true }); setSettings({...systemSettings, invoiceTemplate: template}); showSuccess("تم حفظ قالب الفاتورة بنجاح"); } catch(e) { showError("حدث خطأ أثناء حفظ القالب"); } }; return (<div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700"><h3 className="font-black text-lg mb-6 text-slate-800 dark:text-white flex items-center gap-2"><PrinterIcon className="text-indigo-600" size={20}/> تخصيص شكل الفاتورة</h3><div className="grid grid-cols-1 md:grid-cols-2 gap-6"><div className="space-y-4"><h4 className="font-bold text-sm text-slate-600 dark:text-slate-400 border-b pb-2">عناصر الفاتورة</h4>{[{ key: 'showLogo', label: 'عرض الشعار' },{ key: 'showStoreName', label: 'عرض اسم المتجر' },{ key: 'showCustomerInfo', label: 'عرض معلومات العميل' },{ key: 'showItems', label: 'عرض الأصناف' },{ key: 'showPrices', label: 'عرض الأسعار' },{ key: 'showDiscount', label: 'عرض الخصم' },{ key: 'showTax', label: 'عرض الضريبة' },{ key: 'showFees', label: 'عرض الرسوم الإضافية' },{ key: 'showFooter', label: 'عرض تذييل الفاتورة' },{ key: 'showPaymentMethod', label: 'عرض طريقة الدفع' },{ key: 'showNotes', label: 'عرض الملاحظات' },{ key: 'showTechnician', label: 'عرض اسم الفني' }].map(opt => (<label key={opt.key} className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-900 rounded-xl cursor-pointer"><input type="checkbox" className="w-4 h-4 accent-indigo-600" checked={template[opt.key]} onChange={e => setTemplate({...template, [opt.key]: e.target.checked})} /><span className="text-xs font-bold">{opt.label}</span></label>))}</div><div className="space-y-4"><h4 className="font-bold text-sm text-slate-600 dark:text-slate-400 border-b pb-2">إعدادات الطباعة</h4><div><label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2">حجم الخط</label><select className="w-full border border-slate-200 dark:border-slate-700 p-3 rounded-xl font-bold outline-none focus:border-indigo-500 text-sm bg-white dark:bg-slate-900" value={template.fontSize} onChange={e => setTemplate({...template, fontSize: e.target.value})}><option value="small">صغير</option><option value="normal">عادي</option><option value="large">كبير</option></select></div><div><label className="block text-xs font-bold text-slate-500 dark:text-slate-400 mb-2">حجم الورق</label><select className="w-full border border-slate-200 dark:border-slate-700 p-3 rounded-xl font-bold outline-none focus:border-indigo-500 text-sm bg-white dark:bg-slate-900" value={template.paperSize} onChange={e => setTemplate({...template, paperSize: e.target.value})}><option value="58mm">58 مم (فاتورة صغيرة)</option><option value="80mm">80 مم (فاتورة عادية)</option><option value="A4">A4</option></select></div><div className="mt-6 p-4 bg-indigo-50 dark:bg-indigo-900/30 rounded-xl border border-indigo-100 dark:border-indigo-800"><h5 className="font-bold text-xs text-indigo-900 dark:text-indigo-300 mb-2">معاينة سريعة</h5><div className="bg-white dark:bg-slate-900 p-3 rounded-lg text-[10px]"><p className="font-black text-center">{systemSettings.storeName}</p>{template.showItems && (<div className="border-t border-dashed my-2 pt-2"><p>منتج 1 ........ 100 ج</p><p>منتج 2 ........ 200 ج</p></div>)}{template.showPrices && <p className="font-black mt-2">الإجمالي: 300 ج</p>}</div></div></div></div><div className="mt-6 flex justify-end"><button onClick={handleSave} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:bg-indigo-700 transition-colors flex items-center gap-2"><Save size={16}/> حفظ قالب الفاتورة</button></div></div>); }

