function TransferManager() { const { user } = useAuth(); const { warehouses, warehouseMap } = useSettings(); const [transfers, setTransfers] = useState([]); const [filteredTransfers, setFilteredTransfers] = useState([]); const [loading, setLoading] = useState(true); const [inventory, setInventory] = useState([]); const [searchTerm, setSearchTerm] = useState(''); const [statusFilter, setStatusFilter] = useState('all'); const [showAddModal, setShowAddModal] = useState(false); const [selectedProduct, setSelectedProduct] = useState(null); const [productSearch, setProductSearch] = useState(''); const [requestQty, setRequestQty] = useState(1); const [toWarehouse, setToWarehouse] = useState(''); const [requestNotes, setRequestNotes] = useState(''); const [isSubmitting, setIsSubmitting] = useState(false); const [selectedTransfer, setSelectedTransfer] = useState(null); const [rejectReason, setRejectReason] = useState(''); const [showApproveModal, setShowApproveModal] = useState(false); const [showRejectModal, setShowRejectModal] = useState(false); const [processingId, setProcessingId] = useState(null); const [stats, setStats] = useState({ pending: 0, approved: 0, rejected: 0, totalItems: 0 }); const currentWarehouseId = user?.assignedWarehouseId || 'main'; const canApprove = user?.role === 'admin' || user?.role === 'main_warehouse_manager'; useEffect(() => { const unsubTransfers = onSnapshot(query(collection(db, 'transfers'), orderBy('createdAt', 'desc')), (snap) => { const data = snap.docs.map(d => ({ id: d.id, ...d.data() })); setTransfers(data); setStats({ pending: data.filter(t => t.status === 'pending').length, approved: data.filter(t => t.status === 'approved').length, rejected: data.filter(t => t.status === 'rejected').length, totalItems: data.reduce((s, t) => s + (t.requestedQty || 0), 0) }); setLoading(false); }); const unsubInventory = onSnapshot(query(collection(db, 'inventory'), where('warehouseId', '==', currentWarehouseId), where('isDeleted', '==', false)), (snap) => { setInventory(snap.docs.map(d => ({ id: d.id, ...d.data() }))); }); return () => { unsubTransfers(); unsubInventory(); }; }, [currentWarehouseId]); useEffect(() => { let filtered = [...transfers]; if (searchTerm) { const term = searchTerm.toLowerCase(); filtered = filtered.filter(t => t.itemName?.toLowerCase().includes(term) || t.serialNumber?.toLowerCase().includes(term) || t.requestedBy?.toLowerCase().includes(term)); } if (statusFilter !== 'all') filtered = filtered.filter(t => t.status === statusFilter); setFilteredTransfers(filtered); }, [transfers, searchTerm, statusFilter]); const handleProductSearch = (e) => { e.preventDefault(); if (!productSearch.trim()) return; const found = inventory.find(i => i.serialNumber?.toLowerCase().includes(productSearch.toLowerCase()) || i.name?.toLowerCase().includes(productSearch.toLowerCase())); if (found) { setSelectedProduct(found); setProductSearch(''); } else showError("المنتج غير موجود في مخزنك"); }; const handleCreateTransfer = async () => { if (!selectedProduct || !toWarehouse || requestQty <= 0 || requestQty > selectedProduct.quantity) { showError("بيانات غير صالحة"); return; } setIsSubmitting(true); try { await addDoc(collection(db, 'transfers'), { serialNumber: selectedProduct.serialNumber, itemName: selectedProduct.name, requestedQty: Number(requestQty), fromWarehouseId: currentWarehouseId, fromWarehouseName: warehouseMap[currentWarehouseId], toWarehouseId: toWarehouse, toWarehouseName: warehouseMap[toWarehouse], status: 'pending', requestedBy: user?.name, requestedById: user?.id, notes: requestNotes, createdAt: serverTimestamp() }); showSuccess("تم إرسال الطلب"); setShowAddModal(false); setSelectedProduct(null); setRequestQty(1); setToWarehouse(''); setRequestNotes(''); } catch(e) { showError("فشل إرسال الطلب"); } finally { setIsSubmitting(false); } }; const handleApprove = async (transfer) => { setProcessingId(transfer.id); try { await runTransaction(db, async (t) => { const fromQ = query(collection(db, 'inventory'), where('serialNumber', '==', transfer.serialNumber), where('warehouseId', '==', transfer.fromWarehouseId), where('isDeleted', '==', false)); const fromSnap = await getDocs(fromQ); if (fromSnap.empty) throw new Error("المنتج غير موجود"); const fromItem = fromSnap.docs[0]; if (fromItem.data().quantity < transfer.requestedQty) throw new Error("الكمية غير كافية"); t.update(fromItem.ref, { quantity: increment(-transfer.requestedQty) }); const toQ = query(collection(db, 'inventory'), where('serialNumber', '==', transfer.serialNumber), where('warehouseId', '==', transfer.toWarehouseId), where('isDeleted', '==', false)); const toSnap = await getDocs(toQ); if (toSnap.empty) { const newRef = doc(collection(db, 'inventory')); t.set(newRef, { ...fromItem.data(), warehouseId: transfer.toWarehouseId, quantity: transfer.requestedQty, createdAt: serverTimestamp() }); } else { t.update(toSnap.docs[0].ref, { quantity: increment(transfer.requestedQty) }); } t.update(doc(db, 'transfers', transfer.id), { status: 'approved', processedAt: serverTimestamp(), processedBy: user?.name }); }); showSuccess("تمت الموافقة"); setShowApproveModal(false); setSelectedTransfer(null); } catch(e) { showError(e.message || "فشل الموافقة"); } finally { setProcessingId(null); } }; const handleReject = async () => { if (!selectedTransfer || !rejectReason.trim()) { showError("سبب الرفض مطلوب"); return; } setProcessingId(selectedTransfer.id); try { await updateDoc(doc(db, 'transfers', selectedTransfer.id), { status: 'rejected', rejectReason, processedAt: serverTimestamp(), processedBy: user?.name }); showSuccess("تم رفض الطلب"); setShowRejectModal(false); setSelectedTransfer(null); setRejectReason(''); } catch(e) { showError("فشل الرفض"); } finally { setProcessingId(null); } }; const pendingRequests = filteredTransfers.filter(t => t.status === 'pending'); const processedRequests = filteredTransfers.filter(t => t.status !== 'pending'); return (<div className="space-y-6 text-right" dir="rtl">{showAddModal && (<div className="fixed inset-0 bg-black/60 z-[100] flex items-center justify-center p-4"><div className="bg-white dark:bg-slate-800 rounded-2xl p-6 w-full max-w-lg">{!selectedProduct ? (<div><label className="block text-xs font-bold mb-1">ابحث عن منتج</label><form onSubmit={handleProductSearch} className="flex gap-2"><input className="flex-1 border p-3 rounded-xl" placeholder="الاسم أو السيريال" value={productSearch} onChange={e => setProductSearch(e.target.value)} /><button type="submit" className="bg-indigo-600 text-white px-4 rounded-xl"><Search size={18} /></button></form></div>) : (<div className="space-y-4"><div className="bg-indigo-50 p-4 rounded-xl"><div className="flex justify-between"><div><p className="font-bold">{selectedProduct.name}</p><p className="text-xs font-mono text-indigo-700">{selectedProduct.serialNumber}</p></div><button onClick={() => setSelectedProduct(null)} className="text-indigo-500"><X size={16} /></button></div><div className="flex justify-between text-sm"><span>المتوفر:</span><span className="font-bold">{selectedProduct.quantity}</span></div></div><div><label className="block text-xs font-bold mb-1">الكمية</label><input type="number" min="1" max={selectedProduct.quantity} className="w-full border p-3 rounded-xl text-center" value={requestQty} onChange={e => setRequestQty(Math.min(Number(e.target.value), selectedProduct.quantity) || 1)} /></div><div><label className="block text-xs font-bold mb-1">إلى مخزن</label><select className="w-full border p-3 rounded-xl" value={toWarehouse} onChange={e => setToWarehouse(e.target.value)}><option value="">-- اختر --</option>{warehouses.filter(w => w.id !== currentWarehouseId).map(w => <option key={w.id} value={w.id}>{w.name}</option>)}</select></div><div><label className="block text-xs font-bold mb-1">ملاحظات</label><textarea rows="2" className="w-full border p-3 rounded-xl resize-none" value={requestNotes} onChange={e => setRequestNotes(e.target.value)} /></div><div className="flex gap-3 pt-4"><button onClick={handleCreateTransfer} disabled={isSubmitting} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold">{isSubmitting ? <Loader2 className="animate-spin mx-auto" size={20} /> : 'إرسال'}</button><button onClick={() => setShowAddModal(false)} className="flex-1 bg-slate-100 py-3 rounded-xl font-bold">إلغاء</button></div></div>)}</div></div>)}<ConfirmModal isOpen={showApproveModal} onClose={() => { setShowApproveModal(false); setSelectedTransfer(null); }} onConfirm={() => handleApprove(selectedTransfer)} title="موافقة" message={`الموافقة على تحويل ${selectedTransfer?.requestedQty} قطعة من ${selectedTransfer?.itemName}؟`} type="info" confirmText="موافقة" /><ConfirmModal isOpen={showRejectModal} onClose={() => { setShowRejectModal(false); setSelectedTransfer(null); setRejectReason(''); }} onConfirm={handleReject} title="رفض" message={<div><p>رفض طلب تحويل {selectedTransfer?.requestedQty} قطعة من {selectedTransfer?.itemName}</p><textarea className="w-full border p-3 rounded-xl mt-3" placeholder="سبب الرفض..." value={rejectReason} onChange={e => setRejectReason(e.target.value)} rows="3" /></div>} type="danger" confirmText="رفض" /><div className="grid grid-cols-4 gap-4"><div className="bg-gradient-to-br from-blue-50 p-5 rounded-2xl"><p className="text-xs text-blue-600">قيد الانتظار</p><p className="text-3xl font-black text-blue-700">{stats.pending}</p></div><div className="bg-gradient-to-br from-emerald-50 p-5 rounded-2xl"><p className="text-xs text-emerald-600">تمت الموافقة</p><p className="text-3xl font-black text-emerald-700">{stats.approved}</p></div><div className="bg-gradient-to-br from-rose-50 p-5 rounded-2xl"><p className="text-xs text-rose-600">مرفوض</p><p className="text-3xl font-black text-rose-700">{stats.rejected}</p></div><div className="bg-gradient-to-br from-purple-50 p-5 rounded-2xl"><p className="text-xs text-purple-600">إجمالي القطع</p><p className="text-3xl font-black text-purple-700">{stats.totalItems}</p></div></div><div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border overflow-hidden"><div className="p-4 border-b bg-slate-50 flex flex-wrap gap-3"><div className="relative flex-1"><Search size={16} className="absolute right-3 top-3 text-slate-400" /><input className="w-full bg-white border pr-9 p-2.5 rounded-lg text-sm" placeholder="بحث..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div><select className="border p-2.5 rounded-lg text-sm" value={statusFilter} onChange={e => setStatusFilter(e.target.value)}><option value="all">كل الحالات</option><option value="pending">قيد الانتظار</option><option value="approved">تمت الموافقة</option><option value="rejected">مرفوض</option></select><button onClick={() => setShowAddModal(true)} className="bg-indigo-600 text-white px-4 py-2.5 rounded-lg text-sm">طلب تحويل</button></div><div className="p-4"><h3 className="font-bold mb-4">الطلبات المعلقة ({pendingRequests.length})</h3><div className="overflow-x-auto"><table className="w-full text-sm"><thead className="bg-slate-50 text-xs border-b"><tr><th className="p-4">من مخزن</th><th className="p-4">إلى مخزن</th><th className="p-4">المنتج</th><th className="p-4 text-center">الكمية</th><th className="p-4">طلب بواسطة</th><th className="p-4">التاريخ</th><th className="p-4 text-center">الإجراءات</th></tr></thead><tbody>{pendingRequests.map(req => (<tr key={req.id} className="hover:bg-slate-50"><td className="p-4 font-medium text-indigo-600">{warehouseMap[req.fromWarehouseId]}</td><td className="p-4 font-medium text-indigo-600">{warehouseMap[req.toWarehouseId]}</td><td className="p-4"><p className="font-bold">{req.itemName}</p><p className="text-[10px] font-mono text-slate-400">{req.serialNumber}</p></td><td className="p-4 text-center font-black">{req.requestedQty}</td><td className="p-4 text-xs"><p className="font-bold">{req.requestedBy}</p></td><td className="p-4 text-xs">{formatDate(req.createdAt)}</td><td className="p-4 text-center">{canApprove ? <div className="flex justify-center gap-2"><button onClick={() => { setSelectedTransfer(req); setShowApproveModal(true); }} className="p-1.5 bg-emerald-50 text-emerald-600 rounded-lg"><Check size={18} /></button><button onClick={() => { setSelectedTransfer(req); setShowRejectModal(true); }} className="p-1.5 bg-rose-50 text-rose-600 rounded-lg"><X size={18} /></button></div> : <span className="text-xs text-amber-600">قيد الانتظار</span>}</td></tr>))}</tbody></table></div></div><div className="p-4 border-t"><h3 className="font-bold mb-4">سجل التحويلات ({processedRequests.length})</h3><div className="overflow-x-auto"><table className="w-full text-sm"><thead className="bg-slate-50 text-xs border-b"><tr><th className="p-4">من مخزن</th><th className="p-4">إلى مخزن</th><th className="p-4">المنتج</th><th className="p-4 text-center">الكمية</th><th className="p-4">الحالة</th><th className="p-4">التاريخ</th><th className="p-4">تاريخ المعالجة</th></tr></thead><tbody>{processedRequests.map(req => (<tr key={req.id} className="hover:bg-slate-50"><td className="p-4 font-medium text-indigo-600">{warehouseMap[req.fromWarehouseId]}</td><td className="p-4 font-medium text-indigo-600">{warehouseMap[req.toWarehouseId]}</td><td className="p-4"><p className="font-bold">{req.itemName}</p><p className="text-[10px] font-mono text-slate-400">{req.serialNumber}</p></td><td className="p-4 text-center font-black">{req.requestedQty}</td><td className="p-4">{req.status === 'approved' ? <span className="bg-emerald-100 text-emerald-700 px-2 py-1 rounded-lg text-[10px] font-bold"><Check size={12} /> تمت الموافقة</span> : <div><span className="bg-rose-100 text-rose-700 px-2 py-1 rounded-lg text-[10px] font-bold"><X size={12} /> مرفوض</span>{req.rejectReason && <p className="text-[9px] text-rose-600 mt-1">{req.rejectReason}</p>}</div>}</td><td className="p-4 text-xs">{formatDate(req.createdAt)}</td><td className="p-4 text-xs">{req.processedAt ? formatDate(req.processedAt) : '-'}</td></tr>))}</tbody></table></div></div></div></div>); }

